		public static DateTime CeilingTo(this DateTime value, TimeSpan timeSpan)
		{
			long num = value.Ticks % timeSpan.Ticks;
			if (num == 0L)
			{
				return value;
			}
			return new DateTime(value.Ticks - num + timeSpan.Ticks, value.Kind);
		}

