		public static IEnumerable<DateTime> GetDaysOfWeekForCurrMonth(this DateTime date, DayOfWeek dayOfWeek)
		{
			DateTime dateTime = new DateTime(date.Year, date.Month, 1);
			DateTime dateTime2 = dateTime.AddMonths(1);
			while (dateTime < dateTime2 && dateTime.DayOfWeek != dayOfWeek)
			{
				dateTime = dateTime.AddDays(1.0);
			}
			while (dateTime < dateTime2)
			{
				yield return dateTime;
				dateTime = dateTime.AddDays(7.0);
			}
		}
	}
	public static class DateTimeIntervalExtensions
	{
		public static TimeSpan GetLength(this Interval<DateTime> interval)
		{
			return TimeSpan.FromTicks(Math.Abs(interval.From.Ticks - interval.To.Ticks));
		}

		public static IEnumerable<Interval<DateTime>> Split(this Interval<DateTime> interval, TimeSpan step, bool roundToStep = false)
		{
			if (step == TimeSpan.Zero || step == Timeout.InfiniteTimeSpan)
			{
				yield return interval;
				yield break;
			}
			DateTime dateTime;
			DateTime to;
			if (interval.IsReversal)
			{
				to = interval.From;
				do
				{
					dateTime = to.Add(-step);
					if (roundToStep)
					{
						dateTime = dateTime.CeilingTo(step);
					}
					if (dateTime < interval.To)
					{
						dateTime = interval.To;
					}
					yield return new Interval<DateTime>(dateTime, to);
					to = dateTime;
				}
				while (dateTime > interval.To);
				yield break;
			}
			dateTime = interval.From;
			do
			{
				to = dateTime.Add(step);
				if (roundToStep)
				{
					to = to.FloorTo(step);
				}
				if (to > interval.To)
				{
					to = interval.To;
				}
				yield return new Interval<DateTime>(dateTime, to);
				dateTime = to;
			}
			while (to.Ticks < interval.To.Ticks);
		}

		public static bool Contains(this Interval<DateTime> interval, Period period)
		{
			DateTime value = interval.From;
			DateTime dateTime = interval.To;
			if (interval.IsReversal)
			{
				value = interval.To;
				dateTime = interval.From;
			}
			dateTime = dateTime.AddTicks(1L);
			long ticks = value.CeilingTo(period).Ticks;
			long ticks2 = dateTime.FloorTo(period).Ticks;
			return period.Ticks <= ticks2 - ticks;
		}
	}
