			{
				return double.NaN;
			}
			double num = ((double)OptionMath.CalculateDaysToExpire(ExpirationDate) - shift) / 365.0;
			if (num <= 0.0)
			{
				num = (double)OptionMath.CalculateDaysToExpire(ExpirationDate) / 365.0;
			}
			double num2 = 0.0;
			double num3 = 0.0;
			double num4 = 1E-05;
			if (optionPrice == 0.0 || underlierPrice == 0.0 || StrikePrice == 0.0 || num <= 0.0)
			{
				return 0.0;
			}
			if (underlierPrice <= optionPrice)
			{
				return 0.0;
			}
			double num5 = 0.1;
			if (OptionType == OptionType.Call)
			{
				while (num2 <= optionPrice)
				{
					while (true)
					{
						double num6 = (Math.Log(underlierPrice / StrikePrice) + (Int_Rate + num4 * num4 / 2.0) * num) / (num4 * Math.Sqrt(num));
						double x = num6 - num4 * Math.Sqrt(num);
						num2 = underlierPrice * NormDist(num6) - StrikePrice * Math.Exp(-1.0 * (Int_Rate * num)) * NormDist(x);
						if (!(num2 > optionPrice) || !(num5 > 1E-05) || !(num4 > 0.0001))
						{
							break;
						}
						num4 -= num5;
						num5 *= 0.1;
						num4 += num5;
					}
					if (num2 > optionPrice)
					{
						return num4;
					}
					num4 += num5;
					if (num4 > 10000.0)
					{
						return double.NaN;
					}
				}
				return num4;
			}
			while (num3 <= optionPrice)
			{
				while (true)
				{
					double num6 = (Math.Log(underlierPrice / StrikePrice) + (Int_Rate + num4 * num4 / 2.0) * num) / (num4 * Math.Sqrt(num));
					double x = num6 - num4 * Math.Sqrt(num);
					num3 = StrikePrice * Math.Exp(-1.0 * (Int_Rate * num)) * NormDist(0.0 - x) - underlierPrice * NormDist(0.0 - num6);
					if (!(num3 > optionPrice) || !(num5 > 1E-05) || !(num4 > 0.0001))
					{
						break;
					}
					num4 -= num5;
					num5 *= 0.1;
					num4 += num5;
				}
				if (num3 > optionPrice)
				{
					return num4;
				}
				num4 += num5;
				if (num4 > 10000.0)
				{
					return double.NaN;
				}
			}
			return num4;
		}

