		public override double Theta(DateTime ExpirationDate, double StrikePrice, OptionType OptionType, double price, double IV, double int_Rate, double shift)
		{
			double num = ((double)OptionMath.CalculateDaysToExpire(ExpirationDate) - shift) / 365.0;
			if (num <= 0.0)
			{
				num = (double)OptionMath.CalculateDaysToExpire(ExpirationDate) / 365.0;
			}
			double num2 = (Math.Log(price / StrikePrice) + (int_Rate + IV * IV / 2.0) * num) / (IV * Math.Sqrt(num));
			double num3 = num2 - IV * Math.Sqrt(num);
			if (OptionType == OptionType.Call)
			{
				return (-1.0 * (price * (Math.Exp(-1.0 * num2 * num2 / 2.0) / Math.Sqrt(Math.PI * 2.0)) * IV) / (2.0 * Math.Sqrt(num)) - int_Rate * StrikePrice * Math.Exp(-1.0 * (int_Rate * num)) * NormDist(num3)) / 365.0;
			}
			return (-1.0 * (price * (Math.Exp(-1.0 * num2 * num2 / 2.0) / Math.Sqrt(Math.PI * 2.0)) * IV) / (2.0 * Math.Sqrt(num)) + int_Rate * StrikePrice * Math.Exp(-1.0 * (int_Rate * num)) * NormDist(0.0 - num3)) / 365.0;
		}

