		public override double Vega(DateTime ExpirationDate, double StrikePrice, OptionType OptionType, double price, double IV, double int_Rate, double shift)
		{
			double num = ((double)OptionMath.CalculateDaysToExpire(ExpirationDate) - shift) / 365.0;
			if (num <= 0.0)
			{
				num = (double)OptionMath.CalculateDaysToExpire(ExpirationDate) / 365.0;
			}
			double num2 = (Math.Log(price / StrikePrice) + (int_Rate + IV * IV / 2.0) * num) / (IV * Math.Sqrt(num));
			Math.Sqrt(num);
			return price * Math.Sqrt(num) * (Math.Exp(-1.0 * num2 * num2 / 2.0) / Math.Sqrt(Math.PI * 2.0)) / 100.0;
		}

		public override double Rho(Symbol option, double IV, double int_Rate, double shift)
