		public override double Rho(DateTime ExpirationDate, double StrikePrice, OptionType OptionType, double price, double IV, double int_Rate, double shift)
		{
			double num = StrikePrice;
			double num2 = ((double)OptionMath.CalculateDaysToExpire(ExpirationDate) - shift) / 365.0;
			if (num2 <= 0.0)
			{
				num2 = (double)OptionMath.CalculateDaysToExpire(ExpirationDate) / 365.0;
			}
			double num3 = (Math.Log(price / num) + (int_Rate + IV * IV / 2.0) * num2) / (IV * Math.Sqrt(num2)) - IV * Math.Sqrt(num2);
			if (OptionType != OptionType.Call)
			{
