	public class OptionMath
	{
		public static double GetOptionLastPrice(Symbol optSymbol, OptionPriceType optionPriceType)
		{
			double result = double.NaN;
			if (optionPriceType == OptionPriceType.Ask)
			{
				result = optSymbol.Ask;
			}
			else if (optionPriceType == OptionPriceType.BidAsk && (!optSymbol.Ask.IsNanOrDefault() || optSymbol.Bid.IsNanOrDefault()))
			{
				result = (optSymbol.Ask + optSymbol.Bid) / 2.0;
			}
			else
			{
				switch (optionPriceType)
				{
				case OptionPriceType.Bid:
					result = optSymbol.Bid;
					break;
				case OptionPriceType.Last:
					result = optSymbol.Last;
					break;
				}
			}
			return result;
		}

		public static int CalculateDaysToExpire(DateTime expDate)
		{
			return (int)(expDate - Core.Instance.TimeUtils.DateTimeUtcNow).TotalDays + 1;
		}
	}
	public enum PriceModels
	{
		BlackScholes,
		Binominal,
		Native
	}
	public enum OptionPriceType
	{
		Ask,
		Bid,
		BidAsk,
		Last
	}
	public abstract class PriceModel
	{
		public abstract PriceModels Type { get; }

		public static PriceModel CreateModel(PriceModels type)
		{
			return type switch
			{
				PriceModels.BlackScholes => new BlackScholesPriceModel(), 
				PriceModels.Native => new NativePriceModel(), 
				_ => null, 
			};
		}

		public virtual bool IsCalculationAllowed(Symbol symbol, OptionPriceType priceType)
		{
			if (symbol?.Underlier == null)
			{
				return false;
			}
			return priceType switch
			{
				OptionPriceType.Bid => !symbol.Bid.IsNanOrDefault(), 
				OptionPriceType.Ask => !symbol.Ask.IsNanOrDefault(), 
				OptionPriceType.Last => !symbol.Last.IsNanOrDefault(), 
				_ => true, 
			};
		}

		protected abstract double NormDist(double x);

		public abstract double IV(Symbol option, OptionPriceType priceType, double Int_Rate, double shift);

		public abstract double IV(DateTime ExpirationDate, double StrikePrice, OptionType OptionType, double optionPrice, double underlierPrice, OptionPriceType priceType, double Int_Rate, double shift);

		public abstract double TheorPrice(Symbol option, double IV, double Int_Rate, double shift);

		public abstract double TheorPrice(DateTime ExpirationDate, double StrikePrice, OptionType OptionType, double price, double IV, double Int_Rate, double shift);

		public abstract double Delta(Symbol option, double IV, double Int_Rate, double shift);

		public abstract double Delta(DateTime ExpirationDate, double StrikePrice, OptionType OptionType, double price, double IV, double Int_Rate, double shift);

		public abstract double Vega(Symbol option, double IV, double int_Rate, double shift);

		public abstract double Vega(DateTime ExpirationDate, double StrikePrice, OptionType OptionType, double price, double IV, double Int_Rate, double shift);

		public abstract double Gamma(Symbol option, double IV, double int_Rate, double shift);

		public abstract double Gamma(DateTime ExpirationDate, double StrikePrice, OptionType OptionType, double price, double IV, double Int_Rate, double shift);

		public abstract double Theta(Symbol option, double IV, double int_Rate, double shift);

		public abstract double Theta(DateTime ExpirationDate, double StrikePrice, OptionType OptionType, double price, double IV, double Int_Rate, double shift);

		public abstract double Rho(Symbol option, double IV, double int_Rate, double shift);

		public abstract double Rho(DateTime ExpirationDate, double StrikePrice, OptionType OptionType, double price, double IV, double Int_Rate, double shift);
	}
