	public static class HistoryStepsCalculator
	{
		public static List<Interval<DateTime>> GetSteps(DateTime from, DateTime to, BasePeriod basePeriod, int multiplier, ISessionsContainer sessionsContainer, TimeZone timezone)
		{
			List<Interval<DateTime>> list = new List<Interval<DateTime>>();
			try
			{
				long sessionOffset = sessionsContainer.GetSessionOffset(timezone, basePeriod == BasePeriod.Week, applyNegativeSignForInDaySession: false);
				long num = Period.TicksInBasePeriod(basePeriod) * multiplier;
				long num2 = from.Ticks / num * num + sessionOffset;
				long num3;
				for (num3 = (to.Ticks / num + 1) * num + sessionOffset; num3 < to.Ticks; num3 += num)
				{
				}
				if (num3 > to.Ticks)
				{
					while (num3 - num > to.Ticks)
					{
						num3 -= num;
					}
				}
				while (num2 > from.Ticks)
				{
					num2 -= num;
				}
				if (num2 < from.Ticks)
				{
					for (; num2 + num < from.Ticks; num2 += num)
					{
					}
				}
				switch (basePeriod)
				{
				case BasePeriod.Month:
					num2 = new DateTime(from.Year, from.Month, 1, 0, 0, 0, DateTimeKind.Utc).AddTicks(sessionOffset).Ticks;
					num3 = new DateTime(to.Year, to.Month, 1, 0, 0, 0, DateTimeKind.Utc).AddMonths(1).AddTicks(sessionOffset).Ticks;
					break;
				case BasePeriod.Year:
					num2 = new DateTime(from.Year, 1, 1, 0, 0, 0, DateTimeKind.Utc).AddTicks(sessionOffset).Ticks;
					num3 = new DateTime(to.Year, 1, 1, 0, 0, 0, DateTimeKind.Utc).AddYears(1).AddTicks(sessionOffset).Ticks;
					break;
				}
				DateTime date = new DateTime(num2, DateTimeKind.Utc);
				while (date.Ticks < num3)
				{
					Interval<DateTime> item = GetNextStep(date, basePeriod, multiplier);
					date = item.To;
					if (sessionsContainer != null)
					{
						TimeSpan timeSpan = SessionsExtensions.?(item.From, sessionsContainer.TimeZone);
						if (timeSpan != TimeSpan.Zero)
						{
							item = new Interval<DateTime>(item.From - timeSpan, item.To - timeSpan);
						}
					}
					list.Add(item);
				}
			}
			catch (Exception ex)
			{
				Core.Instance.Loggers.Log(ex);
			}
			return list;
		}

		public static Interval<DateTime> GetNextStep(DateTime date, BasePeriod basePeriod, int multiplier)
		{
			long value = Period.TicksInBasePeriod(basePeriod) * multiplier;
			DateTime dateTime = date;
			DateTime to = basePeriod switch
			{
				BasePeriod.Month => AddMonths(dateTime, multiplier), 
				BasePeriod.Year => dateTime.AddYears(multiplier), 
				_ => date.AddTicks(value), 
			};
			return new Interval<DateTime>(dateTime, to);
		}

		/// <summary>
		/// https://stackoverflow.com/questions/3060381/datetime-addmonths-adding-only-month-not-days
		/// ????????:
		/// (29 Feb).AddMonth(1) = 29 March
		/// </summary>
		public static DateTime AddMonths(DateTime date, int monthsCount)
		{
			if (date.Day != DateTime.DaysInMonth(date.Year, date.Month))
			{
				return date.AddMonths(monthsCount);
			}
			return date.AddDays(1.0).AddMonths(monthsCount).AddDays(-1.0);
		}
	}
